using System.ComponentModel;
using System.Net;
using Microsoft.Extensions.AI;
using OpenAI;

// ─── Notes storage ───
var notes = new List<string>();

// ─── Tool definitions ───
var tools = new AIFunction[]
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(AddNote),
    AIFunctionFactory.Create(GetNotes),
};

// ─── Configure chat client ───
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient();

// ─── Get research topic ───
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔬 Researching: {topic}\n");

// ─── Seed the conversation ───
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your task is to research a topic thoroughly:
        1. Use search_web with varied queries to gather information from multiple angles.
        2. Use add_note to record important findings after each search.
        3. Perform at least 3 searches before concluding.
        4. After gathering enough information, call get_notes to review your findings,
           then write a comprehensive summary with key points and sources.
        Be methodical and curious—explore different facets of the topic.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary:\n\n{topic}"),
};

var options = new ChatOptions { Tools = [.. tools] };

// ─── Agent loop ───
const int maxIterations = 25;
for (int i = 0; i < maxIterations; i++)
{
    var response = await client.GetResponseAsync(messages, options);

    // Append all response messages to the conversation history
    foreach (var msg in response.Messages)
        messages.Add(msg);

    // Find tool calls in the response
    var functionCalls = response.Messages
        .SelectMany(m => m.Contents.OfType<FunctionCallContent>())
        .ToList();

    if (functionCalls.Count == 0)
    {
        // No tool calls means the agent is done—print the final answer
        var answer = response.Messages.LastOrDefault()?.Text;
        Console.WriteLine("\n════════════════════════════════════════");
        Console.WriteLine("  📋  RESEARCH SUMMARY");
        Console.WriteLine("════════════════════════════════════════\n");
        Console.WriteLine(answer ?? "(No summary produced)");
        break;
    }

    // Execute each tool call
    foreach (var call in functionCalls)
    {
        var result = await call.InvokeAsync(tools);
        messages.Add(new ChatMessage(ChatRole.Tool, [result]));
    }
}

// ─── Tool implementations ───

[Description("Searches the web for information on a given query and returns relevant snippets.")]
string SearchWeb([Description("The search query string")] string query)
{
    Console.WriteLine($"  🔍  Searching: \"{query}\"");

    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) ResearchAgent/1.0");

    try
    {
        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
        var html = http.GetStringAsync(url).GetAwaiter().GetResult();

        var results = new List<string>();
        var marker = "result__snippet";
        var idx = 0;

        for (int r = 0; r < 6 && idx >= 0; r++)
        {
            idx = html.IndexOf(marker, idx, StringComparison.Ordinal);
            if (idx == -1) break;

            var start = html.IndexOf('>', idx) + 1;
            var end = html.IndexOf('<', start);
            if (start > 0 && end > start)
            {
                var snippet = WebUtility.HtmlDecode(html[start..end]).Trim();
                if (!string.IsNullOrWhiteSpace(snippet))
                    results.Add(snippet);
            }
            idx = end;
        }

        if (results.Count == 0)
            return "No results found. Try rephrasing the query.";

        return string.Join("\n", results.Select((s, i) => $"[{i + 1}] {s}"));
    }
    catch (Exception ex)
    {
        return $"Search error: {ex.Message}";
    }
}

[Description("Saves a research note for later reference when writing the final summary.")]
string AddNote([Description("The note content to save")] string note)
{
    notes.Add(note);
    Console.WriteLine($"  📝  Note saved ({notes.Count} total)");
    return $"Note saved. Total notes: {notes.Count}";
}

[Description("Retrieves all previously saved research notes.")]
string GetNotes()
{
    if (notes.Count == 0) return "No notes saved yet.";
    Console.WriteLine($"  📖  Reviewing {notes.Count} note(s)");
    return string.Join("\n---\n", notes.Select((n, i) => $"[Note {i + 1}]\n{n}"));
}

